INSERT INTO connector_registry (tenant_id, service_name, category, integration_mode, auth_type, base_url_env, required_credentials, optional_credentials, implementation_status, notes, docs_reference) VALUES ('default', 'antigravity', 'developer_tools', 'local_bridge', 'custom_bridge_or_none', 'ANTIGRAVITY_BASE_URL', '[]'::jsonb, '["ANTIGRAVITY_BASE_URL", "ANTIGRAVITY_ACCESS_TOKEN"]'::jsonb, 'placeholder_bridge', 'Official docs exist, but no stable public REST contract was available for direct package automation here. The adapter creates a structured local handoff bundle instead.', 'https://antigravity.google/docs/home') ON CONFLICT (tenant_id, service_name) DO UPDATE SET category=EXCLUDED.category, integration_mode=EXCLUDED.integration_mode, auth_type=EXCLUDED.auth_type, base_url_env=EXCLUDED.base_url_env, required_credentials=EXCLUDED.required_credentials, optional_credentials=EXCLUDED.optional_credentials, implementation_status=EXCLUDED.implementation_status, notes=EXCLUDED.notes, docs_reference=EXCLUDED.docs_reference, updated_at=now();
