INSERT INTO connector_registry (tenant_id, service_name, category, integration_mode, auth_type, base_url_env, required_credentials, optional_credentials, implementation_status, notes, docs_reference) VALUES ('default', 'azure_ml', 'mlops', 'rest_api', 'oauth_bearer_or_client_credentials', 'AZURE_ML_BASE_URL', '["AZURE_ML_BASE_URL"]'::jsonb, '["AZURE_ML_BEARER_TOKEN", "AZURE_ML_TENANT_ID", "AZURE_ML_CLIENT_ID", "AZURE_ML_CLIENT_SECRET", "AZURE_ML_SUBSCRIPTION_ID", "AZURE_ML_RESOURCE_GROUP", "AZURE_ML_WORKSPACE"]'::jsonb, 'live_api', 'Execution supports either AZURE_ML_BEARER_TOKEN or client-credentials token minting from AZURE_ML_TENANT_ID, AZURE_ML_CLIENT_ID, and AZURE_ML_CLIENT_SECRET. Retry 429/5xx and validate the workspace API version you target.', 'https://learn.microsoft.com/en-us/rest/api/azureml/') ON CONFLICT (tenant_id, service_name) DO UPDATE SET category=EXCLUDED.category, integration_mode=EXCLUDED.integration_mode, auth_type=EXCLUDED.auth_type, base_url_env=EXCLUDED.base_url_env, required_credentials=EXCLUDED.required_credentials, optional_credentials=EXCLUDED.optional_credentials, implementation_status=EXCLUDED.implementation_status, notes=EXCLUDED.notes, docs_reference=EXCLUDED.docs_reference, updated_at=now();
